// src/core/Scene.ts
class Scene2 {
  renderer;
  logger;
  scene;
  entities = new Map;
  activeCamera = null;
  constructor(renderer, logger) {
    this.renderer = renderer;
    this.logger = logger;
    this.scene = new Scene;
    this.scene.background = new Color(8900331);
    this.scene.fog = new Fog(8900331, 10, 100);
    this.logger.debug("Scene created");
  }
  get threeScene() {
    return this.scene;
  }
  get camera() {
    return this.activeCamera;
  }
  setCamera(camera) {
    this.activeCamera = camera;
    this.logger.debug("Camera set as active");
  }
  addEntity(entity) {
    if (this.entities.has(entity.id)) {
      this.logger.warn(`Entity with id ${entity.id} already exists`);
      return;
    }
    this.entities.set(entity.id, entity);
    this.scene.add(entity.object3D);
    this.logger.debug(`Entity ${entity.id} added to scene`);
  }
  removeEntity(entityId) {
    const entity = this.entities.get(entityId);
    if (!entity) {
      this.logger.warn(`Entity with id ${entityId} not found`);
      return;
    }
    this.scene.remove(entity.object3D);
    this.entities.delete(entityId);
    this.logger.debug(`Entity ${entityId} removed from scene`);
  }
  getEntity(entityId) {
    return this.entities.get(entityId);
  }
  getAllEntities() {
    return Array.from(this.entities.values());
  }
  findEntitiesByName(name) {
    return Array.from(this.entities.values()).filter((entity) => entity.name === name);
  }
  findEntitiesByType(type) {
    return Array.from(this.entities.values()).filter((entity) => entity.type === type);
  }
  clearEntities() {
    for (const entity of this.entities.values()) {
      this.scene.remove(entity.object3D);
    }
    this.entities.clear();
    this.logger.debug("All entities cleared from scene");
  }
  setBackground(color) {
    this.scene.background = new Color(color);
  }
  setFog(color, near, far) {
    this.scene.fog = new Fog(color, near, far);
  }
  addAmbientLight(color, intensity = 0.5) {
    const light = new AmbientLight(color, intensity);
    this.scene.add(light);
    this.logger.debug("Ambient light added to scene");
    return light;
  }
  addDirectionalLight(color, intensity = 1, position = new Vector3(5, 10, 5)) {
    const light = new DirectionalLight(color, intensity);
    light.position.copy(position);
    light.castShadow = true;
    light.shadow.mapSize.width = 2048;
    light.shadow.mapSize.height = 2048;
    light.shadow.camera.near = 0.5;
    light.shadow.camera.far = 50;
    light.shadow.camera.left = -20;
    light.shadow.camera.right = 20;
    light.shadow.camera.top = 20;
    light.shadow.camera.bottom = -20;
    this.scene.add(light);
    this.logger.debug("Directional light added to scene");
    return light;
  }
  addPointLight(color, intensity = 1, position = new Vector3(0, 5, 0), distance = 100) {
    const light = new PointLight(color, intensity, distance);
    light.position.copy(position);
    light.castShadow = true;
    this.scene.add(light);
    this.logger.debug("Point light added to scene");
    return light;
  }
  update() {
    for (const entity of this.entities.values()) {
      if (entity.update) {
        entity.update();
      }
    }
  }
  dispose() {
    this.clearEntities();
    this.scene.traverse((object) => {
      if (object instanceof Mesh) {
        object.geometry?.dispose();
        if (Array.isArray(object.material)) {
          object.material.forEach((material) => material.dispose());
        } else {
          object.material?.dispose();
        }
      }
    });
    this.logger.debug("Scene disposed");
  }
}
function createSceneEntity(id, name, type, object3D) {
  return {
    id,
    name,
    type,
    object3D
  };
}

// src/input/InputManager.ts
class InputManager {
  domElement;
  logger;
  keyboard = {};
  mouse = {
    x: 0,
    y: 0,
    deltaX: 0,
    deltaY: 0,
    leftButton: false,
    rightButton: false,
    middleButton: false,
    wheelDelta: 0
  };
  gamepads = [];
  touch = {
    touches: [],
    active: false
  };
  lastMouseX = 0;
  lastMouseY = 0;
  actions = new Map;
  eventListeners = [];
  isInitialized = false;
  constructor(domElement, logger) {
    this.domElement = domElement;
    this.logger = logger;
  }
  get keyboardState() {
    return this.keyboard;
  }
  get mouseState() {
    return this.mouse;
  }
  get gamepadStates() {
    return this.gamepads;
  }
  get touchState() {
    return this.touch;
  }
  initialize() {
    if (this.isInitialized) {
      this.logger.warn("Input manager already initialized");
      return;
    }
    this.setupKeyboardEvents();
    this.setupMouseEvents();
    this.setupGamepadEvents();
    this.setupTouchEvents();
    this.isInitialized = true;
    this.logger.debug("Input manager initialized");
  }
  update() {
    this.mouse.deltaX = 0;
    this.mouse.deltaY = 0;
    this.mouse.wheelDelta = 0;
    this.updateGamepads();
  }
  isKeyPressed(key) {
    return this.keyboard[key.toLowerCase()] || false;
  }
  isMouseButtonPressed(button) {
    switch (button) {
      case "left":
        return this.mouse.leftButton;
      case "right":
        return this.mouse.rightButton;
      case "middle":
        return this.mouse.middleButton;
      default:
        return false;
    }
  }
  getMousePosition() {
    return new Vector2(this.mouse.x, this.mouse.y);
  }
  getMouseCanvasPosition() {
    const rect = this.domElement.getBoundingClientRect();
    return new Vector2(this.mouse.x - rect.left, this.mouse.y - rect.top);
  }
  getMouseNormalized() {
    const rect = this.domElement.getBoundingClientRect();
    return new Vector2((this.mouse.x - rect.left) / rect.width * 2 - 1, -((this.mouse.y - rect.top) / rect.height) * 2 + 1);
  }
  isGamepadConnected(index = 0) {
    return index < this.gamepads.length && this.gamepads[index].connected;
  }
  getGamepadAxis(gamepadIndex, axisIndex) {
    if (!this.isGamepadConnected(gamepadIndex))
      return 0;
    return this.gamepads[gamepadIndex].axes[axisIndex] || 0;
  }
  isGamepadButtonPressed(gamepadIndex, buttonIndex) {
    if (!this.isGamepadConnected(gamepadIndex))
      return false;
    return this.gamepads[gamepadIndex].buttons[buttonIndex] || false;
  }
  getActiveTouches() {
    return this.touch.touches.filter((touch) => touch.force > 0);
  }
  registerAction(action) {
    this.actions.set(action.name, action);
    this.logger.debug(`Input action registered: ${action.name}`);
  }
  unregisterAction(actionName) {
    if (this.actions.delete(actionName)) {
      this.logger.debug(`Input action unregistered: ${actionName}`);
    }
  }
  setCursorLock(locked) {
    if (locked) {
      this.domElement.requestPointerLock();
    } else {
      document.exitPointerLock();
    }
  }
  isCursorLocked() {
    return document.pointerLockElement === this.domElement;
  }
  setupKeyboardEvents() {
    const handleKeyDown = (event) => {
      const key = event.code.toLowerCase();
      this.keyboard[key] = true;
      this.triggerAction("keyboard", key, event);
    };
    const handleKeyUp = (event) => {
      const key = event.code.toLowerCase();
      this.keyboard[key] = false;
      this.triggerAction("keyboard", key, event);
    };
    document.addEventListener("keydown", handleKeyDown);
    document.addEventListener("keyup", handleKeyUp);
    this.eventListeners.push(() => {
      document.removeEventListener("keydown", handleKeyDown);
      document.removeEventListener("keyup", handleKeyUp);
    });
  }
  setupMouseEvents() {
    const handleMouseMove = (event) => {
      this.mouse.x = event.clientX;
      this.mouse.y = event.clientY;
      this.mouse.deltaX = event.clientX - this.lastMouseX;
      this.mouse.deltaY = event.clientY - this.lastMouseY;
      this.lastMouseX = event.clientX;
      this.lastMouseY = event.clientY;
    };
    const handleMouseDown = (event) => {
      switch (event.button) {
        case 0:
          this.mouse.leftButton = true;
          break;
        case 1:
          this.mouse.middleButton = true;
          break;
        case 2:
          this.mouse.rightButton = true;
          break;
      }
      this.triggerAction("mouse", `button${event.button}`, event);
    };
    const handleMouseUp = (event) => {
      switch (event.button) {
        case 0:
          this.mouse.leftButton = false;
          break;
        case 1:
          this.mouse.middleButton = false;
          break;
        case 2:
          this.mouse.rightButton = false;
          break;
      }
      this.triggerAction("mouse", `button${event.button}`, event);
    };
    const handleWheel = (event) => {
      this.mouse.wheelDelta = event.deltaY;
      this.triggerAction("mouse", "wheel", event);
    };
    this.domElement.addEventListener("mousemove", handleMouseMove);
    this.domElement.addEventListener("mousedown", handleMouseDown);
    this.domElement.addEventListener("mouseup", handleMouseUp);
    this.domElement.addEventListener("wheel", handleWheel);
    this.eventListeners.push(() => {
      this.domElement.removeEventListener("mousemove", handleMouseMove);
      this.domElement.removeEventListener("mousedown", handleMouseDown);
      this.domElement.removeEventListener("mouseup", handleMouseUp);
      this.domElement.removeEventListener("wheel", handleWheel);
    });
  }
  setupGamepadEvents() {
    const handleGamepadConnected = (event) => {
      this.logger.debug(`Gamepad connected: ${event.gamepad.index}`);
    };
    const handleGamepadDisconnected = (event) => {
      this.logger.debug(`Gamepad disconnected: ${event.gamepad.index}`);
    };
    window.addEventListener("gamepadconnected", handleGamepadConnected);
    window.addEventListener("gamepaddisconnected", handleGamepadDisconnected);
    this.eventListeners.push(() => {
      window.removeEventListener("gamepadconnected", handleGamepadConnected);
      window.removeEventListener("gamepaddisconnected", handleGamepadDisconnected);
    });
  }
  setupTouchEvents() {
    const handleTouchStart = (event) => {
      this.touch.active = true;
      this.updateTouchPoints(event);
      this.triggerAction("touch", "start", event);
    };
    const handleTouchMove = (event) => {
      this.updateTouchPoints(event);
      this.triggerAction("touch", "move", event);
    };
    const handleTouchEnd = (event) => {
      this.updateTouchPoints(event);
      if (this.touch.touches.length === 0) {
        this.touch.active = false;
      }
      this.triggerAction("touch", "end", event);
    };
    this.domElement.addEventListener("touchstart", handleTouchStart);
    this.domElement.addEventListener("touchmove", handleTouchMove);
    this.domElement.addEventListener("touchend", handleTouchEnd);
    this.eventListeners.push(() => {
      this.domElement.removeEventListener("touchstart", handleTouchStart);
      this.domElement.removeEventListener("touchmove", handleTouchMove);
      this.domElement.removeEventListener("touchend", handleTouchEnd);
    });
  }
  updateGamepads() {
    const gamepads = navigator.getGamepads();
    for (let i = 0;i < gamepads.length; i++) {
      const gamepad = gamepads[i];
      if (!gamepad) {
        if (i < this.gamepads.length) {
          this.gamepads[i].connected = false;
        }
        continue;
      }
      if (i >= this.gamepads.length) {
        this.gamepads.push({
          connected: false,
          index: i,
          axes: [],
          buttons: []
        });
      }
      const state = this.gamepads[i];
      state.connected = true;
      state.index = i;
      state.axes = Array.from(gamepad.axes);
      state.buttons = Array.from(gamepad.buttons).map((button) => button.pressed);
    }
  }
  updateTouchPoints(event) {
    this.touch.touches = Array.from(event.touches).map((touch) => ({
      id: touch.identifier,
      x: touch.clientX,
      y: touch.clientY,
      force: touch.force || 0
    }));
  }
  triggerAction(type, input, event) {
    for (const action of this.actions.values()) {
      if (action.type === type && action.inputs.includes(input)) {
        const inputEvent = {
          type: action.name,
          timestamp: performance.now(),
          data: event
        };
        action.callback?.(inputEvent);
      }
    }
  }
  dispose() {
    for (const removeListener of this.eventListeners) {
      removeListener();
    }
    this.eventListeners.length = 0;
    this.keyboard = {};
    this.gamepads.length = 0;
    this.touch.touches.length = 0;
    this.touch.active = false;
    this.actions.clear();
    this.isInitialized = false;
    this.logger.debug("Input manager disposed");
  }
}

