// src/core/Engine.ts
class Engine {
  config;
  time;
  logger;
  assetManager;
  renderer = null;
  scene = null;
  inputManager = null;
  physicsWorld = null;
  audioEngine = null;
  networkManager = null;
  ecsWorld = null;
  uiManager = null;
  scriptingSystem = null;
  isInitialized = false;
  isRunning = false;
  animationId = null;
  constructor(config) {
    this.config = {
      enablePhysics: true,
      enableAudio: true,
      enableNetworking: false,
      targetFPS: 60,
      enableDebug: false,
      ...config
    };
    this.time = new Time;
    this.logger = new Logger(this.config.enableDebug);
    this.assetManager = new AssetManager(this.logger);
  }
  async initialize() {
    if (this.isInitialized) {
      this.logger.warn("Engine already initialized");
      return;
    }
    try {
      this.logger.info("Initializing engine...");
      await this.initializeRenderer();
      this.initializeScene();
      this.initializeInput();
      this.initializeECS();
      if (this.config.enablePhysics) {
        await this.initializePhysics();
      }
      if (this.config.enableAudio) {
        await this.initializeAudio();
      }
      if (this.config.enableNetworking) {
        await this.initializeNetworking();
      }
      this.initializeUI();
      this.initializeScripting();
      this.isInitialized = true;
      this.logger.info("Engine initialization complete");
    } catch (error2) {
      this.logger.error("Failed to initialize engine:", error2);
      throw error2;
    }
  }
  start() {
    if (!this.isInitialized) {
      throw new Error("Engine must be initialized before starting");
    }
    if (this.isRunning) {
      this.logger.warn("Engine already running");
      return;
    }
    this.isRunning = true;
    this.time.start();
    this.logger.info("Starting engine...");
    this.gameLoop();
  }
  stop() {
    if (!this.isRunning) {
      return;
    }
    this.isRunning = false;
    this.time.stop();
    if (this.animationId !== null) {
      cancelAnimationFrame(this.animationId);
      this.animationId = null;
    }
    this.logger.info("Engine stopped");
  }
  dispose() {
    this.stop();
    this.physicsWorld?.dispose();
    this.audioEngine?.dispose();
    this.networkManager?.dispose();
    this.renderer?.dispose();
    this.inputManager?.dispose();
    this.assetManager.dispose();
    this.uiManager?.dispose();
    this.scriptingSystem?.dispose();
    this.logger.info("Engine disposed");
  }
  get systems() {
    return {
      time: this.time,
      logger: this.logger,
      renderer: this.renderer,
      scene: this.scene,
      input: this.inputManager,
      physics: this.physicsWorld,
      audio: this.audioEngine,
      networking: this.networkManager,
      assets: this.assetManager,
      ecs: this.ecsWorld,
      ui: this.uiManager,
      scripting: this.scriptingSystem
    };
  }
  async initializeRenderer() {
    this.renderer = new Renderer(this.config.canvas, this.logger);
    await this.renderer.initialize();
    this.logger.debug("Renderer initialized");
  }
  initializeScene() {
    if (!this.renderer) {
      throw new Error("Renderer must be initialized before scene");
    }
    this.scene = new Scene2(this.renderer, this.logger);
    this.logger.debug("Scene initialized");
  }
  initializeInput() {
    if (!this.renderer) {
      throw new Error("Renderer must be initialized before input");
    }
    this.inputManager = new InputManager(this.renderer.domElement, this.logger);
    this.logger.debug("Input manager initialized");
  }
  async initializePhysics() {
    this.physicsWorld = new PhysicsWorld(this.logger);
    await this.physicsWorld.initialize();
    this.logger.debug("Physics world initialized");
  }
  async initializeAudio() {
    this.audioEngine = new AudioEngine(this.logger);
    await this.audioEngine.initialize();
    this.logger.debug("Audio engine initialized");
  }
  async initializeNetworking() {
    this.networkManager = new NetworkManager(this.logger);
    await this.networkManager.initialize();
    this.logger.debug("Network manager initialized");
  }
  initializeECS() {
    this.ecsWorld = new ECSWorld(this.logger);
    this.logger.debug("ECS world initialized");
  }
  initializeUI() {
    this.uiManager = new UIManager(this.logger);
    this.logger.debug("UI manager initialized");
  }
  initializeScripting() {
    this.scriptingSystem = new ScriptingSystem(this.logger);
    this.logger.debug("Scripting system initialized");
  }
  gameLoop = () => {
    if (!this.isRunning) {
      return;
    }
    this.time.update();
    this.update(this.time.deltaTime);
    this.render();
    this.animationId = requestAnimationFrame(this.gameLoop);
  };
  update(deltaTime) {
    this.inputManager?.update();
    this.physicsWorld?.update(deltaTime);
    this.ecsWorld?.update(deltaTime);
    this.audioEngine?.update();
    this.networkManager?.update();
    this.uiManager?.update(deltaTime);
    this.scriptingSystem?.update(deltaTime);
  }
  render() {
    if (!this.renderer || !this.scene) {
      return;
    }
    const camera = this.scene.camera;
    if (!camera) {
      this.logger.warn("No camera set in scene, skipping render");
      return;
    }
    this.renderer.render(this.scene.threeScene, camera);
  }
}

// src/examples/BasicExample.ts
class BasicExample {
  engine;
  cube = null;
  scene;
  renderer;
  input;
  physics;
  ecs;
  ui;
  constructor(engine) {
    this.engine = engine;
  }
  async initialize() {
    console.log("\uD83C\uDFAE Initializing BasicExample...");
    const { scene, renderer, input, physics, ecs, ui } = this.engine.systems;
    this.scene = scene;
    this.renderer = renderer;
    this.input = input;
    this.physics = physics;
    this.ecs = ecs;
    this.ui = ui;
    console.log("\uD83D\uDCCA Creating HUD...");
    ui.createHUD();
    console.log("\uD83D\uDCD6 Creating help overlay...");
    this.createHelpOverlay();
    console.log("\uD83D\uDCF7 Setting up camera...");
    this.setupCamera();
    console.log("\uD83D\uDCA1 Setting up lighting...");
    this.setupLighting();
    console.log("\uD83C\uDFAF Creating scene objects...");
    await this.createSceneObjects();
    console.log("⌨️ Setting up input handling...");
    this.setupInput();
    console.log("\uD83E\uDDE9 Creating ECS entities...");
    this.createECSEntities();
    setTimeout(() => {
      this.showWelcomeMessage();
    }, 1000);
    console.log("✅ Basic example initialized");
    console.log("\uD83D\uDCDD Note: HUD and scene updates will be handled by the main engine game loop");
  }
  setupCamera() {
    const { scene } = this.engine.systems;
    const camera = new PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.set(5, 5, 5);
    camera.lookAt(0, 0, 0);
    scene.setCamera(camera);
  }
  setupLighting() {
    const { scene } = this.engine.systems;
    scene.addAmbientLight(4210752, 0.4);
    const directionalLight = scene.addDirectionalLight(16777215, 1, new Vector3(10, 10, 5));
    scene.addPointLight(16739179, 0.5, new Vector3(-3, 2, 0), 20);
  }
  async createSceneObjects() {
    const groundGeometry = new PlaneGeometry(20, 20);
    const groundMaterial = new MeshLambertMaterial({
      color: 8421504,
      side: DoubleSide
    });
    const ground = new Mesh(groundGeometry, groundMaterial);
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    const groundEntity = createSceneEntity("ground", "Ground", "environment", ground);
    this.scene.addEntity(groundEntity);
    if (this.physics) {
      const groundBody = this.physics.createPlaneBody(new Vector3(0, 1, 0), new Vector3(0, 0, 0), 0, ground);
      this.physics.addBody("ground", new PhysicsBody(groundBody, ground));
    }
    const cubeGeometry = new BoxGeometry(1, 1, 1);
    const cubeMaterial = new MeshPhongMaterial({
      color: 65280,
      shininess: 100
    });
    const cube = new Mesh(cubeGeometry, cubeMaterial);
    cube.position.set(0, 0.5, 0);
    cube.castShadow = true;
    cube.receiveShadow = true;
    this.cube = createSceneEntity("cube", "Spinning Cube", "prop", cube);
    this.scene.addEntity(this.cube);
    if (this.physics) {
      const cubeBody = this.physics.createBoxBody(new Vector3(1, 1, 1), new Vector3(0, 0.5, 0), 1, cube);
      this.physics.addBody("cube", new PhysicsBody(cubeBody, cube));
    }
    for (let i = 0;i < 5; i++) {
      const geometry = new BoxGeometry(0.5, 0.5, 0.5);
      const material = new MeshPhongMaterial({
        color: new Color().setHSL(Math.random(), 0.7, 0.5)
      });
      const mesh = new Mesh(geometry, material);
      mesh.position.set((Math.random() - 0.5) * 8, 2 + Math.random() * 3, (Math.random() - 0.5) * 8);
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      const entity = createSceneEntity(`cube_${i}`, `Decor Cube ${i}`, "prop", mesh);
      this.scene.addEntity(entity);
      if (this.physics) {
        const body = this.physics.createBoxBody(new Vector3(0.5, 0.5, 0.5), mesh.position.clone(), 0.5, mesh);
        this.physics.addBody(`cube_${i}`, new PhysicsBody(body, mesh));
      }
    }
  }
  setupInput() {
    this.input.registerAction({
      name: "move_forward",
      type: "keyboard",
      inputs: ["KeyW"],
      callback: () => {
        this.moveCamera(0, 0, -0.1);
      }
    });
    this.input.registerAction({
      name: "move_backward",
      type: "keyboard",
      inputs: ["KeyS"],
      callback: () => {
        this.moveCamera(0, 0, 0.1);
      }
    });
    this.input.registerAction({
      name: "move_left",
      type: "keyboard",
      inputs: ["KeyA"],
      callback: () => {
        this.moveCamera(-0.1, 0, 0);
      }
    });
    this.input.registerAction({
      name: "move_right",
      type: "keyboard",
      inputs: ["KeyD"],
      callback: () => {
        this.moveCamera(0.1, 0, 0);
      }
    });
    this.input.registerAction({
      name: "jump",
      type: "keyboard",
      inputs: ["Space"],
      callback: () => {
        this.jumpCube();
      }
    });
    this.input.registerAction({
      name: "orbit_camera",
      type: "mouse",
      inputs: ["button0"],
      callback: (event) => {
        if (event.type === "mousedown") {
          this.input.setCursorLock(true);
        }
      }
    });
    this.input.registerAction({
      name: "release_camera",
      type: "keyboard",
      inputs: ["Escape"],
      callback: () => {
        this.input.setCursorLock(false);
      }
    });
  }
  createECSEntities() {
    Promise.resolve().then(() => exports_ECSWorld).then(({ Component: Component2, System: System2 }) => {

      class RotateComponent extends Component2 {
        speed;
        axis;
        constructor(speed = 1, axis = new Vector3(0, 1, 0)) {
          super();
          this.speed = speed;
          this.axis = axis;
        }
      }

      class RotationSystem extends System2 {
        update(deltaTime) {
          if (!this.world)
            return;
          const entities = this.world.getEntitiesWithComponent(RotateComponent);
          for (const entity2 of entities) {
            const rotateComp = this.world.getComponent(entity2.id, RotateComponent);
            if (rotateComp && entity2.active) {
              const visualComp = this.world.getComponent(entity2.id, VisualComponent);
              if (visualComp && visualComp.mesh) {
                visualComp.mesh.rotateOnAxis(rotateComp.axis, rotateComp.speed * deltaTime);
              }
            }
          }
        }
      }

      class VisualComponent extends Component2 {
        mesh;
        constructor(mesh) {
          super();
          this.mesh = mesh;
        }
      }
      this.ecs.addSystem(new RotationSystem);
      const entity = this.ecs.createEntity("spinning_cube");
      this.ecs.addComponent(entity.id, new RotateComponent(2, new Vector3(0, 1, 0)));
      if (this.cube) {
        this.ecs.addComponent(entity.id, new VisualComponent(this.cube.object3D));
      }
    }).catch((error2) => {
      console.warn("⚠️ Failed to load ECS components:", error2);
    });
  }
  moveCamera(x, y, z) {
    if (this.scene.camera) {
      const moveVector = new Vector3(x, y, z);
      moveVector.applyQuaternion(this.scene.camera.quaternion);
      this.scene.camera.position.add(moveVector);
    }
  }
  jumpCube() {
    if (this.physics && this.cube) {
      const body = this.physics.getBody("cube");
      if (body) {
        body.body.velocity.y = 10;
      }
    }
  }
  createHelpOverlay() {
    const helpPanel = this.ui.createElement({
      id: "help-panel",
      type: "panel",
      x: 10,
      y: 10,
      width: 250,
      style: {
        backgroundColor: "rgba(0, 0, 0, 0.8)",
        border: "2px solid #00ff00",
        borderRadius: "10px",
        padding: "15px",
        color: "white",
        fontSize: "14px",
        fontFamily: "monospace",
        pointerEvents: "auto"
      }
    });
    this.ui.createElement({
      id: "help-title",
      type: "text",
      x: 20,
      y: 20,
      text: "\uD83C\uDFAE GAME ENGINE CONTROLS",
      style: {
        color: "#00ff00",
        fontSize: "16px",
        fontWeight: "bold",
        fontFamily: "monospace",
        pointerEvents: "none"
      }
    });
    const controls = [
      "W/A/S/D - Move camera",
      "SPACE - Make cube jump",
      "Mouse Click - Lock camera",
      "ESC - Release camera",
      "H - Toggle this help"
    ];
    controls.forEach((control, index) => {
      this.ui.createElement({
        id: `help-control-${index}`,
        type: "text",
        x: 20,
        y: 50 + index * 20,
        text: control,
        style: {
          color: "#ffffff",
          fontSize: "12px",
          fontFamily: "monospace",
          pointerEvents: "none"
        }
      });
    });
    this.ui.createElement({
      id: "status-indicator",
      type: "text",
      x: 20,
      y: 170,
      text: "✅ Engine Running",
      style: {
        color: "#00ff00",
        fontSize: "12px",
        fontFamily: "monospace",
        pointerEvents: "none"
      }
    });
    this.input.registerAction({
      name: "toggle_help",
      type: "keyboard",
      inputs: ["KeyH"],
      callback: () => {
        const panel = this.ui.getElement("help-panel");
        if (panel) {
          if (panel.visible) {
            panel.hide();
          } else {
            panel.show();
          }
        }
      }
    });
  }
  showWelcomeMessage() {
    this.ui.showNotification("\uD83C\uDFAE Welcome to the Game Engine! Press H to toggle help", 5000);
  }
}

// src/main.ts
async function main() {
  console.log("\uD83D\uDE80 Starting game engine initialization...");
  updateLoadingMessage("Initializing Engine...");
  try {
    const canvasElement = document.getElementById("gameCanvas");
    if (!canvasElement) {
      throw new Error('Canvas element not found. Make sure there is an element with id="gameCanvas"');
    }
    console.log("✅ Canvas element found");
    console.log("\uD83D\uDD27 Creating engine instance...");
    updateLoadingMessage("Creating Engine...");
    const engine = new Engine({
      canvas: canvasElement,
      enablePhysics: true,
      enableAudio: true,
      enableNetworking: false
    });
    console.log("✅ Engine instance created");
    console.log("⚙️ Initializing engine systems...");
    updateLoadingMessage("Initializing Systems...");
    const initTimeout = new Promise((_, reject) => {
      setTimeout(() => reject(new Error("Engine initialization timeout after 10 seconds")), 1e4);
    });
    await Promise.race([engine.initialize(), initTimeout]);
    console.log("✅ Engine initialized successfully");
    console.log("\uD83C\uDFAE Creating basic example...");
    updateLoadingMessage("Loading Example...");
    const example = new BasicExample(engine);
    console.log("\uD83D\uDD27 Initializing example...");
    updateLoadingMessage("Initializing Example...");
    const exampleInitTimeout = new Promise((_, reject) => {
      setTimeout(() => reject(new Error("Example initialization timeout after 5 seconds")), 5000);
    });
    await Promise.race([example.initialize(), exampleInitTimeout]);
    console.log("✅ Example initialized successfully");
    console.log("\uD83C\uDFAF Hiding loading screen...");
    const loadingElement = document.getElementById("loading");
    if (loadingElement) {
      loadingElement.style.display = "none";
      console.log("✅ Loading screen hidden");
    }
    console.log("\uD83C\uDFAC Starting game loop...");
    engine.start();
    console.log("\uD83C\uDF89 Game engine started successfully!");
    window.addEventListener("beforeunload", () => {
      console.log("\uD83E\uDDF9 Cleaning up engine...");
      engine.dispose();
    });
  } catch (error2) {
    console.error("❌ Failed to initialize game engine:", error2);
    console.error("Error details:", {
      name: error2.name,
      message: error2.message,
      stack: error2.stack
    });
    const loadingElement = document.getElementById("loading");
    if (loadingElement) {
      loadingElement.textContent = `Failed to load: ${error2.message}. Check console for details.`;
      loadingElement.style.color = "#ff4444";
      loadingElement.style.fontSize = "18px";
      loadingElement.style.textAlign = "center";
      loadingElement.style.maxWidth = "80%";
    }
  }
}
function updateLoadingMessage(message) {
  const loadingElement = document.getElementById("loading");
  if (loadingElement) {
    loadingElement.textContent = message;
    loadingElement.style.fontSize = "20px";
    loadingElement.style.textAlign = "center";
  }
  console.log(`\uD83D\uDCCB Loading: ${message}`);
}
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", main);
} else {
  main();
}
